jQuery(document).ready(function($){$("#registration-form").on("submit",function(e){e.preventDefault();const formData=$(this).serialize();$.ajax({type:"POST",url:ajax_vars.ajax_url,data:formData+"&action=ajax_user_registration&security="+ajax_vars.registration_nonce,success:function(response){if(response.success){alert(response.data);location.reload();}else{$(".error-messages").html("");response.data.forEach(function(error){$(".error-messages").append("<p>"+error+"</p>");});$(".error-messages").show();}}});});$("#login-form").on("submit",function(e){e.preventDefault();const formData=$(this).serialize();$.ajax({type:"POST",url:ajax_vars.ajax_url,data:formData+"&action=ajax_user_login&security="+ajax_vars.login_nonce,success:function(response){if(response.success){alert(response.data);window.location.href="/";}else{$(".error-messages").html("");response.data.forEach(function(error){$(".error-messages").append("<p>"+error+"</p>");});$(".error-messages").show();}}});});function initFormValidation(){const phoneField=$(".wpcf7-form").find('input[type="tel"]');const submitButton=$(".wpcf7-submit");const errorMessage=$(".phone-error-message");const phonePattern=/^(?:\+?(\d{1,3})[-.\s]?)?(?:\(?(\d{3})\)?[-.\s]?)?(\d{3})[-.\s]?(\d{4})$/;function validatePhone(){const phoneValue=phoneField.val().trim();const cleanedPhoneValue=phoneValue.replace(/\D/g,"");if(phoneValue===""||(phonePattern.test(phoneValue)&&cleanedPhoneValue.length>=10)){errorMessage.hide();submitButton.prop("disabled",false);}else{errorMessage.show();submitButton.prop("disabled",true);}}
phoneField.on("input",function(){validatePhone();});validatePhone();}
initFormValidation();});